<template><div><div class="page-title">首页统计</div><el-row :gutter="16"><el-col :span="6" v-for="card in cards" :key="card.label"><el-card class="stat-card"><div class="num">{{ card.value }}</div><div class="label">{{ card.label }}</div></el-card></el-col></el-row><div class="page-card" style="margin-top:16px"><h3>AI 助手提示</h3><p class="text-muted">右下角可以打开 AI 运维助手，支持设备查询、工单处理、通知查询和系统规则问答。</p></div></div></template>
<script setup>import { ref,onMounted } from 'vue';import { getDeviceStatistics,getWorkOrderStatistics } from '../api/statistics';import { countUnread } from '../api/notice';const cards=ref([{label:'设备总数',value:'-'},{label:'故障设备',value:'-'},{label:'待处理工单',value:'-'},{label:'未读通知',value:'-'}]);function pick(obj,names,fallback=0){for(const name of names){if(obj&&obj[name]!==undefined&&obj[name]!==null)return obj[name]}return fallback}onMounted(async()=>{const [d,w,n]=await Promise.allSettled([getDeviceStatistics(),getWorkOrderStatistics(),countUnread()]);const ds=d.status==='fulfilled'?d.value:{};const ws=w.status==='fulfilled'?w.value:{};cards.value=[{label:'设备总数',value:pick(ds,['totalCount','deviceTotal','total','count'],'-')},{label:'故障设备',value:pick(ds,['faultCount','faultDeviceCount','faultDevice'],'-')},{label:'待处理工单',value:pick(ws,['pendingCount','pendingWorkOrderCount','pendingWorkOrder','todoCount'],'-')},{label:'未读通知',value:n.status==='fulfilled'?n.value:'-'}]})</script>
<style scoped>.stat-card{border-radius:14px}.num{font-size:30px;font-weight:800;color:#2563eb}.label{color:#64748b;margin-top:8px}</style>
